// ── Test: Event Log Statistics ─────────────────────────────────────────────

#[test]
fn test_event_log_statistics() {
    // Create a test log instead of loading from fixtures
    let mut log = EventLog::new();

    let mut trace1 = pictl::models::Trace::new();
    trace1.attributes.insert(
        "case:concept:name".to_string(),
        AttributeValue::String("case1".to_string()),
    );

    let mut event1 = pictl::models::Event::new();
    event1.attributes.insert(
        "activity".to_string(),
        AttributeValue::String("A".to_string()),
    );
    event1.attributes.insert(
        "time:timestamp".to_string(),
        AttributeValue::String("2023-01-01T10:00:00Z".to_string()),
    );

    let mut event2 = pictl::models::Event::new();
    event2.attributes.insert(
        "activity".to_string(),
        AttributeValue::String("B".to_string()),
    );
    event2.attributes.insert(
        "time:timestamp".to_string(),
        AttributeValue::String("2023-01-01T11:00:00Z".to_string()),
    );

    trace1.events.push(event1);
    trace1.events.push(event2);
    log.traces.push(trace1);

    let mut trace2 = pictl::models::Trace::new();
    trace2.attributes.insert(
        "case:concept:name".to_string(),
        AttributeValue::String("case2".to_string()),
    );

    let mut event3 = pictl::models::Event::new();
    event3.attributes.insert(
        "activity".to_string(),
        AttributeValue::String("A".to_string()),
    );
    event3.attributes.insert(
        "time:timestamp".to_string(),
        AttributeValue::String("2023-01-01T12:00:00Z".to_string()),
    );

    trace2.events.push(event3);
    log.traces.push(trace2);

    // Calculate basic statistics
    let num_cases = log.traces.len();
    let num_events: usize = log.traces.iter().map(|t| t.events.len()).sum();

    assert_eq!(num_cases, 2, "Should have 2 cases");
    assert_eq!(num_events, 3, "Should have 3 events");
    assert!(num_events >= num_cases, "Events should be >= cases");
}

#[test]
fn test_activity_frequency_parity() {
    let log = load_event_log_json("running-example.json");

    // Calculate activity frequencies
    let mut activity_counts: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();

    for trace in &log.traces {
        for event in &trace.events {
            if let Some(AttributeValue::String(activity)) = event.attributes.get("activity") {
                *activity_counts.entry(activity.clone()).or_insert(0) += 1;
            }
        }
    }

    assert!(
        !activity_counts.is_empty(),
        "Should have activity frequencies"
    );

    // Verify total events match
    let total_from_activities: usize = activity_counts.values().sum();
    let total_events: usize = log.traces.iter().map(|t| t.events.len()).sum();
    assert_eq!(
        total_from_activities, total_events,
        "Activity frequencies should sum to total events"
    );
}

#[test]
fn test_trace_variant_analysis() {
    let log = load_event_log_json("running-example.json");

    // Group traces by variant (sequence of activities)
    let mut variants: std::collections::HashMap<Vec<String>, usize> =
        std::collections::HashMap::new();

    for trace in &log.traces {
        let activities: Vec<String> = trace
            .events
            .iter()
            .filter_map(|e| {
                e.attributes
                    .get("activity")
                    .and_then(|v| v.as_string())
                    .map(|s| s.to_string())
            })
            .collect();

        *variants.entry(activities).or_insert(0) += 1;
    }

    assert!(!variants.is_empty(), "Should have at least one variant");

    // Verify variant counts match trace count
    let total_from_variants: usize = variants.values().sum();
    assert_eq!(
        total_from_variants,
        log.traces.len(),
        "Variant counts should sum to trace count"
    );
}

